// TestimonialCard.jsx
import React, { useState } from "react";
import { motion } from "framer-motion";

const TestimonialCard = ({ card }) => {
  const [flipped, setFlipped] = useState(false);

  const toggleFlip = () => setFlipped(!flipped);

  return (
    <motion.div
      className="perspective-1000 cursor-pointer mx-2"
      style={{
        width: "clamp(280px, 23.6vw, 360px)",
        height: "clamp(350px, 38.2vh, 450px)"
      }}
      onClick={toggleFlip}
      role="button"
      tabIndex={0}
      onKeyPress={(e) => e.key === "Enter" && toggleFlip()}
      aria-label={`Card de ${card.title}, click para girar`}
      whileHover={{ 
        scale: 1.05,
        y: -10,
        transition: { duration: 0.3 }
      }}
      whileTap={{ scale: 0.95 }}
    >
      <motion.div 
        className={`relative w-full h-full rounded-3xl transition-transform duration-700 transform-style-preserve-3d shadow-2xl select-none ${
          flipped ? 'rotate-y-180' : 'rotate-y-0'
        }`}
        style={{
          background: flipped 
            ? "linear-gradient(135deg, #072D42 0%, #0A3A5A 100%)"
            : "linear-gradient(135deg, #F29E38 0%, #E67E22 100%)"
        }}
        whileHover={{
          boxShadow: "0 25px 50px rgba(0,0,0,0.25)",
          transition: { duration: 0.3 }
        }}
      >
        {/* Frente */}
        <div className="absolute w-full h-full rounded-3xl backface-hidden flex flex-col justify-center items-center p-8 text-center">
          <motion.h3 
            className="font-bodoni font-bold mb-8 text-surface-elevated uppercase tracking-wider select-none"
            style={{
              fontSize: "clamp(1.2rem, 3vw, 1.8rem)",
              lineHeight: "1.2"
            }}
            whileHover={{ scale: 1.05 }}
          >
            {card.title}
          </motion.h3>
          <motion.p 
            className="font-miles leading-relaxed mb-8 break-words text-surface-elevated"
            style={{
              fontSize: "clamp(0.9rem, 2vw, 1.1rem)",
              lineHeight: "1.618"
            }}
            whileHover={{ scale: 1.02 }}
          >
            {card.text}
          </motion.p>
          <motion.div 
            className="font-bodoni font-bold text-surface-elevated select-none"
            style={{
              fontSize: "clamp(1rem, 2.5vw, 1.3rem)"
            }}
            whileHover={{ scale: 1.05 }}
          >
            {card.role}
          </motion.div>
        </div>

        {/* Reverso */}
        <div className="absolute w-full h-full rounded-3xl backface-hidden flex flex-col justify-center items-center p-6 text-center transform rotate-y-180 overflow-y-hidden">
          {card.backType === "list" ? (
            <motion.ul 
              className="list-none p-0 m-0 w-fit text-surface-elevated text-center select-none"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.3 }}
            >
              {card.backContent.map((item, i) => (
                <motion.li 
                  key={i} 
                  className="font-miles my-2"
                  style={{
                    fontSize: "clamp(0.9rem, 2vw, 1.1rem)"
                  }}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ duration: 0.3, delay: 0.5 + i * 0.1 }}
                  whileHover={{ scale: 1.05, x: 5 }}
                >
                  {item}
                </motion.li>
              ))}
            </motion.ul>
          ) : (
            <motion.img
              src={card.backContent}
              alt={`Imagen de ${card.title}`}
              className="rounded-full object-cover select-none mx-auto block"
              style={{
                width: "clamp(120px, 30vw, 180px)",
                height: "clamp(120px, 30vw, 180px)"
              }}
              draggable={false}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5, delay: 0.3 }}
              whileHover={{ scale: 1.1, rotate: 5 }}
            />
          )}
        </div>
      </motion.div>
    </motion.div>
  );
};

export default TestimonialCard;
